  width: 2rem;
  aspect-ratio: 1/1;
  background-color: white;
  border-radius: 2rem;
}
main .shadow {
  top: 0;
  position: absolute;
  transform-origin: bottom center;
  transform: translateY(1rem) translateZ(2rem) rotateX(-90.1deg);
}
main .shadow .digit span {
